def prioritize(candidates: list) -> list:
    now = datetime.now(timezone.utc)
    cutoff = now - timedelta(days=PRIORITY_MAX_DAYS)

    filtered = []
    for c in candidates:
        if len(c["body"]) < PRIORITY_MIN_BODY:
            continue
        try:
            created = datetime.fromisoformat(c["created_at"])
            if created.tzinfo is None:
                created = created.replace(tzinfo=timezone.utc)
            if created < cutoff:
                continue
        except (ValueError, KeyError):
            continue
        filtered.append(c)

    # Sort by body length as a substance proxy
    filtered.sort(key=lambda x: len(x["body"]), reverse=True)

    # Cap per repo for diversity
    repo_counts: dict = {}
    diversified = []
    for c in filtered:
        repo = c.get("repo", "unknown")
        if repo_counts.get(repo, 0) >= MAX_PER_REPO:
            continue
        repo_counts[repo] = repo_counts.get(repo, 0) + 1
        diversified.append(c)

    selected = diversified[:TOP_N]

    console.print(
        f"Prioritized: [bold]{len(filtered)}[/bold] passed filters → "
        f"[bold]{len(diversified)}[/bold] after repo cap → "
        f"[bold green]{len(selected)}[/bold green] selected for classification"
    )
    return selected

