            ].join(' ')}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className={mdClass}>
        <ReactMarkdown remarkPlugins={[remarkGfm]}>
          {moment.artifacts[active]}
        </ReactMarkdown>
      </div>

      {/* Disclaimer */}
      <p className="mt-4 text-xs text-slate-600 italic">
        Draft only — not posted to GitHub or sent to anyone.
      </p>
    </div>
  );
}

