            The full classified set.
          </p>
          <CandidatesTable candidates={data.classified_candidates} />
        </section>
      </div>

      <Footer />

      {/* Modal */}
      <PainMomentModal
        moment={selectedMoment}
        onClose={() => setSelectedMoment(null)}
      />
    </div>
  );
}

